  };\\n}\\n\\nfunction normalizeCurrency(value, field) {\\n  if (typeof value !== \\\"string\\\") {\\n    throw new TypeError(`${field} must be a string.`);\\n  }\\n  const normalized = value.trim().toUpperCase();\\n  if (!/^[A-Z]{3}$/.test(normalized)) {\\n    throw new TypeError(`${field} must be a 3-letter uppercase code.`);\\n  }\\n  return normalized;\\n}\\n\\nfunction normalizeMaxCandidates(value) {\\n  if (!Number.isInteger(value) || value < 1) {\\n    throw new TypeError(\\\"maxCandidates must be a positive integer.\\\");\\n  }\\n  return value;\\n}\\n\\nfunction normalizeSearchText(value) {\\n  return String(value).trim().toLowerCase();\\n}\\n\\nfunction hasSearchTerm(text, term) {\\n  const escaped = term.replace(/[.*+?^${}()|[\\\\]\\\\\\\\]/g, \\\"\\\\\\\\$&\\\");\\n  return new RegExp(`(^|[^a-z0-9])${escaped}([^a-z0-9]|$)`, \\\"i\\\").test(text);\\n}\\n\\nfunction sameSize(left, right) {\\n  return normalizeSearchText(left).replace(/\\\\s+/g, \\\"\\\") === normalizeSearchText(right).replace(/\\\\s+/g, \\\"\\\");\\n}\\n\",\"exit_code\":0,\"status\":\"completed\"}}\n./spec/KAN-29/runs/20260509T141426Z-25603037335/events.jsonl:71:{\"type\":\"item.completed\",\"item\":{\"id\":\"item_38\",\"type\":\"command_execution\",\"command\":\"/bin/zsh -lc \\\"sed -n '1,280p' test/asket-product-search.test.mjs\\\"\",\"aggregated_output\":\"import { mkdtemp, rm, stat } from \\\"node:fs/promises\\\";\\nimport { join } from \\\"node:path\\\";\\nimport { tmpdir } from \\\"node:os\\\";\\nimport test from \\\"node:test\\\";\\nimport assert from \\\"node:assert/strict\\\";\\n\\nimport {\\n  ASKET_RETAILER_IDENTIFIER,\\n  searchAsketProducts,\\n} from \\\"../src/asket-product-search.mjs\\\";\\n\\nconst SHIRT_INTENT = {\\n  garmentClass: \\\"shirt\\\",\\n  size: \\\"M\\\",\\n  colorKeywords: [\\\"white\\\", \\\"off white\\\"],\\n  priceCeiling: { amount: 120, currency: \\\"EUR\\\" },\\n};\\n\\ntest(\\\"returns up to 3 ranked Asket product candidates for a structured intent\\\", 