function normalizeConnectedRetailers(connectedRetailers) {
  if (!Array.isArray(connectedRetailers)) {
    throw new TypeError("connectedRetailers must be an array.");
  }

  return connectedRetailers.map((retailer) => {
    if (!retailer || typeof retailer !== "object" || Array.isArray(retailer)) {
      throw new TypeError("connectedRetailers entries must be objects.");
    }

    return {
      label: normalizeString(retailer.label ?? retailer.retailerIdentifier, "retailer label"),
      discoveryOnly: Boolean(retailer.discoveryOnly),
      statusLabel: Boolean(retailer.discoveryOnly)
        ? "Discovery-only"
        : normalizeString(retailer.statusLabel ?? retailer.status, "retailer status"),
    };
  });
}

function normalizeProposalCards(proposalCards, defaultPriceCeiling) {
  if (!Array.isArray(proposalCards)) {
    throw new TypeError("proposalCards must be an array.");
  }

  return proposalCards.map((proposal) => normalizeProposalCard(proposal, defaultPriceCeiling));
}

function normalizeMemories(memories) {
  if (!Array.isArray(memories)) {
    throw new TypeError("memories must be an array.");
  }
  return memories.map((memory, index) => {
    if (!memory || typeof memory !== "object" || Array.isArray(memory)) {
      throw new TypeError(`memories[${index}] must be an object.`);
    }
    return {
      id: normalizeString(memory.id, `memories[${index}].id`),
      content: normalizeString(memory.content ?? memory.text, `memories[${index}].content`),
      pinned: Boolean(memory.pinned),
      sentiment: normalizeString(memory.sentiment ?? "neutral", `memories[${index}].sentiment`),
      subject: normalizeOptionalSubject(memory.subject, `memories[${index}].subject`),
      tags: normalizeTags(memory.tags, `memories[${index}].tags`),
      timestamp: normalizeString(memory.timestamp, `memories[${index}].timestamp`),
    };
  }).sort((left, right) => Number(right.pinned) - Number(left.pinned) || right.timestamp.localeCompare(left.timestamp));
}

function normalizeShoppingActivityAuditEntries(auditEntries) {
  if (!Array.isArray(auditEntries)) {
    throw new TypeError("auditEntries must be an array.");
  }

  return auditEntries.map((entry, index) => {
    if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
      throw new TypeError(`auditEntries[${index}] must be an object.`);
    }

    return {
      actionType: normalizeString(entry.actionType, `auditEntries[${index}].actionType`),
      retailer: normalizeString(entry.retailer, `auditEntries[${index}].retailer`),
      timestamp: normalizeTimestampString(entry.timestamp, `auditEntries[${index}].timestamp`),
      status: normalizeString(entry.status, `auditEntries[${index}].status`),
      screenshotPath:
        entry.screenshotPath === undefined
          ? undefined
          : normalizeString(entry.screenshotPath, `auditEntries[${index}].screenshotPath`),
    };
  }).sort((left, right) => right.timestamp.localeCompare(left.timestamp));
}

function normalizeTimestampString(value, field) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) {
    throw new TypeError(`${field} must be a valid date or ISO timestamp.`);
  }
  return date.toISOString();
}

function normalizeTags(tags, field) {
  if (!Array.isArray(tags)) {
    throw new TypeError(`${field} must be an array.`);
  }
  return tags.map((tag) => normalizeString(tag, field));
}

function normalizeOptionalSubject(subject, field) {
  if (subject === undefined) {
    return undefined;
  }
  if (!subject || typeof subject !== "object" || Array.isArray(subject)) {
    throw new TypeError(`${field} must be an object.`);
  }
  const normalized = {};
  for (const key of ["brand", "title", "color", "size", "productUrl", "retailer", "category"]) {
    if (subject[key] !== undefined) {
      normalized[key] = normalizeString(subject[key], `${field}.${key}`);
    }
  }
  return normalized;
}

function normalizeProposalCard(proposal, defaultPriceCeiling) {
  if (!proposal || typeof proposal !== "object" || Array.isArray(proposal)) {
    throw new TypeError("proposalCards entries must be objects.");
  }

  const candidates = normalizeProposalCandidates(proposal.candidates ?? []);
  const hasSelectedCandidate = candidates.some((candidate) => candidate.selected);
  const candidatesWithSelection =
    hasSelectedCandidate || candidates.length === 0
      ? candidates
      : candidates.map((candidate, index) => ({
          ...candidate,
          selected: index === 0,
        }));
  const typeConfirmationCeiling = normalizeProposalPriceCeiling(
    proposal.perItemPriceCeiling ?? proposal.priceCeiling ?? defaultPriceCeiling,
    "proposal per-item ceiling",
  );
  const requiresTypeConfirmation = candidatesWithSelection.some((candidate) =>
    candidateExceedsPriceCeiling(candidate, typeConfirmationCeiling),
  );

  return {
    retailer: normalizeString(proposal.retailer ?? proposal.retailerName, "proposal retailer"),
    eta: normalizeString(proposal.eta, "proposal ETA"),
    returnPolicy: normalizeString(proposal.returnPolicy, "proposal return policy"),
    cartUrl: normalizeString(proposal.cartUrl, "proposal cart URL"),
    candidates: candidatesWithSelection,
    discoveryOnly: Boolean(proposal.discoveryOnly ?? proposal.retailerStatus?.discoveryOnly),
    requiresTypeConfirmation,
    typeConfirmationCeiling,
    manualUrl: normalizeString(
      proposal.manualUrl ??
        candidatesWithSelection.find((candidate) => candidate.selected)?.productUrl ??
        candidatesWithSelection[0]?.productUrl ??
        proposal.cartUrl,
      "proposal manual URL",

import { mkdtemp, rm } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import test from "node:test";
import assert from "node:assert/strict";

import {
  SHOPPING_MEMORY_TAG,
  addShoppingMemory,
  clearShoppingMemories,
  createDefaultShoppingProfile,
  pinShoppingMemory,
  readShoppingProfile,
  recordShoppingOutcomeMemory,
  updateShoppingProfile,
  updateShoppingMemory,
  wipeShoppingMemory,
  writeShoppingProfile,
} from "../src/shopping-profile.mjs";

test("creates a complete profile shape with required hard constraints", () => {
  const profile = createDefaultShoppingProfile({
    country: "lv",
    currency: "eur",
    sizes: {
      tops: { value: "M", system: "International" },
      shoes: { value: "42", system: "EU" },
    },
    budgetAnchors: {
      jeans: { amount: 80, cadence: "seasonal", notes: "Wait for sale" },
    },
    hardExclusions: ["leather", "leather", "dry clean only"],
    perItemPriceCeiling: { amount: 150 },
    enabledRetailers: ["Zalando", "ASOS", "Zalando"],
  });

  assert.equal(profile.country, "LV");
  assert.equal(profile.currency, "EUR");
  assert.deepEqual(Object.keys(profile.sizes), ["tops", "shoes"]);
  assert.equal(profile.budgetAnchors.jeans.currency, "EUR");
  assert.equal(profile.budgetAnchors.jeans.cadence, "seasonal");
  assert.equal(profile.budgetAnchors.jeans.notes, "Wait for sale");
  assert.deepEqual(profile.hardExclusions, ["leather", "dry clean only"]);
  assert.equal(createDefaultShoppingProfile().perItemPriceCeiling.amount, 500);
  assert.equal(profile.perItemPriceCeiling.currency, "EUR");
  assert.deepEqual(profile.enabledRetailers, ["Zalando", "ASOS"]);
  assert.deepEqual(profile.memories, []);
});

test("persists profile data so it can be read by a later process", async () => {
  const dir = await mkdtemp(join(tmpdir(), "shopping-profile-"));
  const path = join(dir, "profile.json");

  try {
    await writeShoppingProfile(
      createDefaultShoppingProfile({
        country: "DE",
        currency: "EUR",
        perItemPriceCeiling: { amount: 200 },
        enabledRetailers: ["About You"],
      }),
      path,
    );

    const reloaded = await readShoppingProfile(path);

    assert.equal(reloaded.country, "DE");
    assert.equal(reloaded.perItemPriceCeiling.amount, 200);
    assert.deepEqual(reloaded.enabledRetailers, ["About You"]);
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("updates fields programmatically while preserving existing records", async () => {
  const dir = await mkdtemp(join(tmpdir(), "shopping-profile-"));
  const path = join(dir, "profile.json");

  try {
    await writeShoppingProfile(
